create extension if not exists pgcrypto;
create table if not exists public.market_sources (id uuid primary key default gen_random_uuid(), name text not null, description text null, source_type text not null, url text not null, category text not null, geography text not null default 'Australia', reliability_tier text not null default 'watchlist', enabled boolean not null default true, refresh_frequency_hours integer not null default 24, last_fetched_at timestamptz null, last_success_at timestamptz null, last_error text null, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.market_updates (id uuid primary key default gen_random_uuid(), source_id uuid null references public.market_sources(id) on delete set null, source_name text not null, source_url text not null, source_published_at timestamptz null, ingested_at timestamptz not null default now(), title text not null, slug text null, category text not null, geography jsonb not null default '[]'::jsonb, impact_level text not null default 'medium', audience_tags jsonb not null default '[]'::jsonb, raw_excerpt text null, raw_content_hash text null, ai_summary text null, key_points jsonb not null default '[]'::jsonb, why_it_matters text null, property_implications text null, finance_implications text null, policy_implications text null, risk_flags jsonb not null default '[]'::jsonb, confidence_score numeric null, citation_urls jsonb not null default '[]'::jsonb, relevance_score numeric not null default 0, status text not null default 'candidate', failure_reason text null, dedupe_hash text not null unique, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.market_digests (id uuid primary key default gen_random_uuid(), generated_at timestamptz not null default now(), period_start timestamptz not null, period_end timestamptz not null, executive_summary text not null, top_update_ids jsonb not null default '[]'::jsonb, finance_lending_highlights jsonb not null default '[]'::jsonb, property_market_highlights jsonb not null default '[]'::jsonb, construction_supply_highlights jsonb not null default '[]'::jsonb, policy_regulation_highlights jsonb not null default '[]'::jsonb, political_economic_watchpoints jsonb not null default '[]'::jsonb, buyer_implications text null, investor_implications text null, broker_adviser_implications text null, client_advisory_implications jsonb not null default '[]'::jsonb, recommended_watchlist_for_tomorrow jsonb not null default '[]'::jsonb, source_urls jsonb not null default '[]'::jsonb, confidence_score numeric null, status text not null default 'published', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table if not exists public.market_update_questions (id uuid primary key default gen_random_uuid(), question text not null, answer text not null, source_update_ids jsonb not null default '[]'::jsonb, citation_urls jsonb not null default '[]'::jsonb, confidence_score numeric null, created_by uuid null, created_at timestamptz not null default now());
create index if not exists idx_market_sources_enabled on public.market_sources(enabled); create index if not exists idx_market_sources_category on public.market_sources(category); create index if not exists idx_market_updates_status on public.market_updates(status); create index if not exists idx_market_updates_category on public.market_updates(category); create index if not exists idx_market_updates_impact on public.market_updates(impact_level); create index if not exists idx_market_updates_source_published_at on public.market_updates(source_published_at); create index if not exists idx_market_updates_ingested_at on public.market_updates(ingested_at); create index if not exists idx_market_updates_dedupe_hash on public.market_updates(dedupe_hash); create index if not exists idx_market_digests_generated_at on public.market_digests(generated_at);
alter table public.market_sources enable row level security; alter table public.market_updates enable row level security; alter table public.market_digests enable row level security; alter table public.market_update_questions enable row level security;
drop policy if exists "Authenticated users can read market sources" on public.market_sources; create policy "Authenticated users can read market sources" on public.market_sources for select to authenticated using (true);
drop policy if exists "Authenticated users can read published market updates" on public.market_updates; create policy "Authenticated users can read published market updates" on public.market_updates for select to authenticated using (status = 'published');
drop policy if exists "Authenticated users can read published market digests" on public.market_digests; create policy "Authenticated users can read published market digests" on public.market_digests for select to authenticated using (status = 'published');
drop policy if exists "Authenticated users can insert own market questions" on public.market_update_questions; create policy "Authenticated users can insert own market questions" on public.market_update_questions for insert to authenticated with check (true);
drop policy if exists "Authenticated users can read market questions" on public.market_update_questions; create policy "Authenticated users can read market questions" on public.market_update_questions for select to authenticated using (true);
